import{_ as a,I as l,f as d,i}from"./chunks/framework.BQlZKzZW.js";const _=JSON.parse('{"title":"Casual Think","description":"","frontmatter":{"date":"","draft":false,"title":"Casual Think","BookToC":true,"outline":[1,8],"sidebar":false},"headers":[],"relativePath":"life/casual-think.md","filePath":"life/casual-think.md"}'),o={name:"life/casual-think.md"};function c(n,e,r,s,u,t){return l(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="casual-think" tabindex="-1">Casual Think <a class="header-anchor" href="#casual-think" aria-label="Permalink to “Casual Think”">​</a></h1><h2 id="_2026" tabindex="-1">2026 <a class="header-anchor" href="#_2026" aria-label="Permalink to “2026”">​</a></h2><h3 id="_2026-05" tabindex="-1">2026-05 <a class="header-anchor" href="#_2026-05" aria-label="Permalink to “2026-05”">​</a></h3><h4 id="_2026-05-26-tuesday" tabindex="-1">2026-05-26 Tuesday <a class="header-anchor" href="#_2026-05-26-tuesday" aria-label="Permalink to “2026-05-26 Tuesday”">​</a></h4><ul><li><code>claude code</code> 上配置 <code>deepseek v4</code>，没有在用阿里百炼的 <code>coding plan</code>了。<code>deepseek v4</code> 按量付费，多个对话同时跑不会<code>429</code>。这两天工作高频使用，一天的费用是10块，先用一个月看吧，说不定比200块一个月的订阅便宜呢。即使贵一点，它的效果也还是可以的，加上它可以并发跑，响应速度也不慢 <ul><li>今天还试了一下<code>claude agents</code>，因为 <code>deepseek</code> 可以同时跑多个对话，但好像看不到其他窗口跑的对话，只能先从<code>claude agents</code>里进去，然后在里面发起任务才能看到(2026-05-06)</li></ul></li><li>之前写单元测试还小有心得，现在大部分代码都是用AI生成，感觉单元测试也不是很有必要了，AI犯错的概率比我低多了。感觉让AI review 代码比单元测试更有用</li></ul><h4 id="_2026-05-25-monday" tabindex="-1">2026-05-25 Monday <a class="header-anchor" href="#_2026-05-25-monday" aria-label="Permalink to “2026-05-25 Monday”">​</a></h4><ul><li>广州开始热起来了，下班骑车回去第一件事必须得冲一个澡</li><li>晚上煮面的时候，发现面条发霉了，切掉了一段。。。。冰箱贴也得边缘也长霉了</li></ul><h4 id="_2026-05-24-sunday" tabindex="-1">2026-05-24 Sunday <a class="header-anchor" href="#_2026-05-24-sunday" aria-label="Permalink to “2026-05-24 Sunday”">​</a></h4><ul><li>用 <code>openai whisper</code> 把视频的字幕读取出来，可以本地跑，但 openai 开源的原版工具速度有点慢，还有其他适配 apple 芯片的版本 <ul><li>生成字幕文件(srt)之后，我再用AI帮我把它整理成markdown格式的文章，就可以读了 <ul><li>我用 <code>claude code + qwen-3.6-plus</code> 它是直接帮我生成一个脚本来帮我把字幕文件转换为markdown。。。。。用 <code>claude code + glm-5</code> 它是真正去读取我的内容然后生成文章的，但速度比较慢 <ul><li>现在用 deepseek v4 按量计费，就舍不得这么用了(2026-05-26) PS：如果这么用的话，缓存命中率应该会很低吧 <ul><li>昨天的claude code 对话，今天 resume 之后，缓存命中好像失效了(2026-05-26)</li></ul></li></ul></li></ul></li></ul></li></ul><h4 id="_2026-05-15-friday" tabindex="-1">2026-05-15 Friday <a class="header-anchor" href="#_2026-05-15-friday" aria-label="Permalink to “2026-05-15 Friday”">​</a></h4><ul><li>去年的工作如果有好好用一下AI的话，那真的是能做的更好，更少犯错</li></ul><h4 id="_2026-05-14" tabindex="-1">2026-05-14 <a class="header-anchor" href="#_2026-05-14" aria-label="Permalink to “2026-05-14”">​</a></h4><ul><li>现在使用 <code>claude code</code> 配置的模型是 百炼的 coding plan，如果开2个对话，就老是会报 429，只能一个一个执行，好慢呀， 不知道有什么办法可以同时多开，这样效率就又能提升了 <ul><li>我在我的服务器上还有我的工作电脑上2个地方同时进行对话，还是会被429，指定不同的模型也不行，好像没有办法了</li></ul></li><li>使用 <code>plan mode</code> 一方面可以让你理清思路你想要让AI做什么，另一方面是可以规划好一批任务一次提交给AI，让AI可以持续运行把事情做完，效果更高 <ul><li>我发现即使是在 <code>plan mode</code> 下，它也不出完全不会改动你的工程，它还是会编辑你的工程文件</li></ul></li><li>在windows电脑上，我其实更想用 Terminal 来使用 claude code，感觉 Terminal 上的字体显示更舒服，用 IDEA 的话，有 claude code 的插件可以和 claude code cli 进行交互，我可以选中代码直接发送到cli，如果用 Terminal 就不行</li><li>其实系统中(一致性要求很高)有同步任务也不是说会有什么太大的问题，只要同步逻辑写对的不出问题</li></ul>',13)])])}const m=a(o,[["render",c]]);export{_ as __pageData,m as default};
